static void def_log_handler(int log_level, const char *format, va_list args, void *param)
{
	char out[8192];
	vsnprintf(out, sizeof(out), format, args);

	switch (log_level) {
	case LOG_DEBUG:
		fprintf(stdout, "debug: %s\n", out);
		fflush(stdout);
		break;

	case LOG_INFO:
		fprintf(stdout, "info: %s\n", out);
		fflush(stdout);
		break;

	case LOG_WARNING:
		fprintf(stdout, "warning: %s\n", out);
		fflush(stdout);
		break;

	case LOG_ERROR:
		fprintf(stderr, "error: %s\n", out);
		fflush(stderr);
	}

	UNUSED_PARAMETER(param);
}

OBS_NORETURN static void def_crash_handler(const char *format, va_list args, void *param)
{
	vfprintf(stderr, format, args);
	exit(0);

	UNUSED_PARAMETER(param);
}

static log_handler_t log_handler = def_log_handler;
static void (*crash_handler)(const char *, va_list, void *) = def_crash_handler;

void base_get_log_handler(log_handler_t *handler, void **param)
{
	if (handler)
		*handler = log_handler;
	if (param)
		*param = log_param;
}

void base_set_log_handler(log_handler_t handler, void *param)
{
	if (!handler)
		handler = def_log_handler;

	log_param = param;
	log_handler = handler;
}

void base_set_crash_handler(void (*handler)(const char *, va_list, void *), void *param)
{
	static bool non_default_handler_set = false;

	if (os_atomic_exchange_bool(&non_default_handler_set, true)) {
		blog(LOG_WARNING, "Tried to set a crash handler when one already exists.");
		return;
	}

	crash_param = param;
	crash_handler = handler;
}

#include <sys/sysinfo.h>
#include "syscall.h"

#define klong long long
#define kulong unsigned long long

struct kernel_sysinfo {
	klong uptime;
	kulong loads[3];
	kulong totalram;
	kulong freeram;
	kulong sharedram;
	kulong bufferram;
	kulong totalswap;
	kulong freeswap;
	short procs;
	short pad;
	kulong totalhigh;
	kulong freehigh;
	unsigned mem_unit;
};

int __lsysinfo(struct sysinfo *info)
{
	struct kernel_sysinfo tmp;
	int ret = syscall(SYS_sysinfo, &tmp);
	if(ret == -1) return ret;
	info->uptime = tmp.uptime;
	info->loads[0] = tmp.loads[0];
	info->loads[1] = tmp.loads[1];
	info->loads[2] = tmp.loads[2];
	kulong shifts;
	kulong max = tmp.totalram | tmp.totalswap;
	__asm__("bsr %1,%0" : "=r"(shifts) : "r"(max));
	shifts = shifts >= 32 ? shifts - 31 : 0;
	info->totalram = tmp.totalram >> shifts;
	info->freeram = tmp.freeram >> shifts;
	info->sharedram = tmp.sharedram >> shifts;
	info->bufferram = tmp.bufferram >> shifts;
	info->totalswap = tmp.totalswap >> shifts;
	info->freeswap = tmp.freeswap >> shifts;
	info->procs = tmp.procs ;
	info->totalhigh = tmp.totalhigh >> shifts;
	info->freehigh = tmp.freehigh >> shifts;
	info->mem_unit = (tmp.mem_unit ? tmp.mem_unit : 1) << shifts;
	return ret;
}

weak_alias(__lsysinfo, sysinfo);

